import{c as a,Q as n,j as s,m as e}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"Minecraft 技术原理系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/00-写作计划.md","filePath":"minecraftLearning/00-写作计划.md","lastUpdated":1781677803000}'),i={name:"minecraftLearning/00-写作计划.md"};function o(l,t,r,d,p,c){return n(),s("div",null,[...t[0]||(t[0]=[e(`<h1 id="minecraft-技术原理系列写作计划" tabindex="-1">Minecraft 技术原理系列写作计划 <a class="header-anchor" href="#minecraft-技术原理系列写作计划" aria-label="Permalink to &quot;Minecraft 技术原理系列写作计划&quot;">​</a></h1><blockquote><p>本系列从<strong>引擎与数据模型</strong>视角拆解 Minecraft(以 Java 版为主,1.18+ 为基线)的底层原理:体素世界怎么组织、地形怎么靠种子和噪声生成、区块怎么渲染、世界怎么按 20 TPS 跑起来、数据怎么存盘,以及方块、方块实体、实体、流体、物品、生物群系、光照、注册表这一整套对象模型如何分层咬合。 它不是&quot;生存攻略&quot;也不是&quot;红石教程&quot;,而是面向工程师的&quot;Minecraft 是怎么被造出来的&quot;。</p></blockquote><hr><h2 id="核心定位" tabindex="-1">核心定位 <a class="header-anchor" href="#核心定位" aria-label="Permalink to &quot;核心定位&quot;">​</a></h2><p>很多人玩了几百小时 Minecraft,却从没想过这些问题:</p><ul><li>&quot;无限世界&quot;为什么不会把硬盘撑爆?</li><li>同一块地里的麦子为什么有的先熟有的后熟?</li><li>为什么离开后远处的农场和红石机器会停摆?</li><li>床、箱子这种看起来普通的方块,凭什么是&quot;方块实体&quot;?</li><li>一个坐标上到底叠着多少层数据?</li></ul><p>本系列只回答一类问题:</p><blockquote><p><strong>把 Minecraft 当成一个软件工程作品,讲清楚它的数据模型、存储格式、运行循环和渲染策略,以及这些设计为什么是这样取舍的。</strong></p></blockquote><p>因此本系列默认选择:</p><table tabindex="0"><thead><tr><th>维度</th><th>选择</th><th>原因</th></tr></thead><tbody><tr><td>版本基线</td><td>Java 版,1.18+</td><td>Anvil 存储、分段调色板、世界高度扩展后的现代形态</td></tr><tr><td>视角</td><td>引擎 / 数据结构</td><td>不讲玩法技巧,讲&quot;底层怎么实现的&quot;</td></tr><tr><td>深度</td><td>机制 + 字节级 + 取舍</td><td>关键处下沉到字节布局与算法,并解释为什么这样设计</td></tr><tr><td>边界</td><td>不逐行读源码</td><td>讲清结构与原理,源码类名作为指针给出</td></tr></tbody></table><hr><h2 id="三条主线" tabindex="-1">三条主线 <a class="header-anchor" href="#三条主线" aria-label="Permalink to &quot;三条主线&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>世界怎么&quot;长出来&quot;并被画出来   (体素 → 噪声地形 → 渲染)</span></span>
<span class="line"><span>   → 世界怎么&quot;跑起来&quot;并存下来  (Tick 系统 → 区块生命 → 存储格式)</span></span>
<span class="line"><span>   → 世界由&quot;什么&quot;构成          (方块/实体/流体/物品/… → 注册表 → 总图)</span></span></code></pre></div><p>核心节奏:<strong>前 8 篇打通&quot;生成—运行—存储&quot;的纵向链路,后 4 篇横向铺开整套对象模型并收束成一张架构总图。</strong></p><hr><h2 id="篇目设计-25-篇" tabindex="-1">篇目设计 (25 篇) <a class="header-anchor" href="#篇目设计-25-篇" aria-label="Permalink to &quot;篇目设计 (25 篇)&quot;">​</a></h2><h3 id="第一层-世界的生成与呈现-01-03" tabindex="-1">第一层:世界的生成与呈现 (01-03) <a class="header-anchor" href="#第一层-世界的生成与呈现-01-03" aria-label="Permalink to &quot;第一层:世界的生成与呈现 (01-03)&quot;">​</a></h3><ul><li><strong>01 体素世界、区块与无限地形的存法</strong> (block/voxel 网格 / Chunk 与 16³ Section / 为什么不能逐方块渲染 / &quot;无限世界&quot;靠确定性生成而非全量存储的核心思路)</li><li><strong>02 地形生成:种子、噪声与确定性世界</strong> (Perlin/Simplex/OpenSimplex / 种子+坐标→确定输出 / 多层噪声叠加映射高度温湿度 / 生物群系与矿脉洞穴 / 分阶段生成流水线与 Status)</li><li><strong>03 区块渲染:只画看得见的面</strong> (face culling / 相邻实心面剔除 / 一个 chunk 合并成一个 mesh、一次 draw call / 改一格只重建该 chunk / 内存里的 PalettedContainer 与渲染的对偶)</li></ul><h3 id="第二层-世界怎么跑起来、又怎么存下来-04-08" tabindex="-1">第二层:世界怎么跑起来、又怎么存下来 (04-08) <a class="header-anchor" href="#第二层-世界怎么跑起来、又怎么存下来-04-08" aria-label="Permalink to &quot;第二层:世界怎么跑起来、又怎么存下来 (04-08)&quot;">​</a></h3><ul><li><strong>04 Tick 系统:20 TPS 主循环与三类更新</strong> (时间累加器与&quot;追帧&quot;/掉 TPS / scheduled tick 队列与水流红石延迟 / random tick 抽样与作物参差成熟 / 邻居通知级联与红石 / tile tick 上限)</li><li><strong>05 区块的生命:加载、ticket 等级与模拟距离</strong> (chunk 不是二元加载 / ticket level 距离场 / entity-ticking vs block-ticking vs border / simulation distance / 为什么远处机器停摆、区块加载器原理)</li><li><strong>06 实体系统:脱离网格的自由对象</strong> (Entity vs 方块的本质差异 / 浮点坐标与 AABB 碰撞逐轴裁剪 / 实体层级 / A* 寻路与 Goal/Brain AI / 1.17 起实体单独存储 / 实体为何是 lag 头号来源)</li><li><strong>07 存储(上):Region/Anvil 文件格式逐字节</strong> (为什么打包成 region / 8KB 头:位置表+时间戳表 / 4KB 扇区对齐 / 长度+压缩类型字节 / zlib/LZ4 / 超大 chunk 外置 .mcc / 扇区分配与碎片)</li><li><strong>08 存储(下):NBT 与 Palette 位压缩</strong> (NBT 标签布局与类型表 / chunk NBT 现代结构 / 局部调色板 + bit-packed Long_Array / bitsPerEntry 规则 / 1.16 前后跨界与不跨界 / DataVersion 与版本迁移)</li></ul><h3 id="第三层-世界由什么构成-09-12" tabindex="-1">第三层:世界由什么构成 (09-12) <a class="header-anchor" href="#第三层-世界由什么构成-09-12" aria-label="Permalink to &quot;第三层:世界由什么构成 (09-12)&quot;">​</a></h3><ul><li><strong>09 方块的三层:Block、BlockState 与方块实体</strong> (Block 单例=类型/行为 / BlockState=属性组合与全局调色板 / 为何方块无逐实例数据 / BlockEntity:存数据 vs 特殊渲染 / 床为何是方块实体 / 箱子的物品+开盖动画+大箱子双方块配对)</li><li><strong>10 世界里还有什么:流体、物品、生物群系、光照、粒子</strong> (FluidState 与方块叠加、含水机制、独立 tick / ItemStack 寄生在容器 / Biome 4×4×4 粒度 / 光照双通道与洪水填充传播 / 粒子纯客户端)</li><li><strong>11 注册表、标签、维度与修饰/信号/会话层</strong> (Registry 是一切类型的总账 / 命名空间ID+数字ID / 冻结与进服同步 / 静态 vs 动态注册表 / Tag 分组 / 维度与存档 / 属性·效果·附魔修饰层 / 运行时信号 / 菜单会话层)</li><li><strong>12 分层架构总图与一个方块的生命周期</strong> (类型 vs 实例的正交轴 / 一格上叠多层数据 / &quot;世界里的对象&quot;有限集 vs &quot;引擎系统&quot;开放集 / 一个 16³ section 从生成→运行→存盘→加载的完整时序)</li></ul><h3 id="第四层-到达玩家与玩法系统-13-21" tabindex="-1">第四层:到达玩家与玩法系统 (13-21) <a class="header-anchor" href="#第四层-到达玩家与玩法系统-13-21" aria-label="Permalink to &quot;第四层:到达玩家与玩法系统 (13-21)&quot;">​</a></h3><blockquote><p>前 12 篇讲的是&quot;世界是什么、怎么存、怎么跑&quot;(几乎全是单机/服务端数据模型)。本层补三块盲区:世界怎么<strong>到达玩家</strong>(网络、渲染管线),建在数据模型之上的<strong>玩法级系统</strong>(红石、刷怪、世界生成进阶、指令),以及一条<strong>横向对照</strong>(Bedrock vs Java)。</p></blockquote><ul><li><strong>13 网络与多人同步:集成服务端、预测与插值</strong> (单机也跑集成服务端 / 服务端权威 / 协议分阶段与注册表同步 / chunk 包 / 实体插值与客户端预测、橡皮筋回正)</li><li><strong>14 红石:信号传播、更新顺序与图灵完备</strong> (0-15 衰减 / 中继器比较器 / 邻居级联与硬弱供能 / quasi-connectivity / 更新顺序与 0-tick/BUD/observer / 逻辑门到红石计算机 / Java vs Bedrock 差异根源)</li><li><strong>15 刷怪机制:mobcap、光照条件与 ticking 耦合</strong> (刷怪循环 / 分类 mobcap 与区块数成比例 / 位置/光照/距离条件 / despawn 与 persistent / 与 ticking 范围耦合 / 刷怪塔原理)</li><li><strong>16 世界生成进阶:密度函数 router、多噪声生物群系与拼图结构</strong> (1.18 密度函数 router / multi-noise 六气候参数 / 生物群系与地形解耦 / spline 高度 / aquifer 与噪声洞 / jigsaw 结构生成)</li><li><strong>17 数据组件与 DataFixerUpper:物品新模型与版本迁移</strong> (1.20.5 物品=类型化组件映射 / 默认组件与差异覆盖 / 为何取代 NBT tag / DFU 按 DataVersion 重写升级链 / 走向强类型可迁移)</li><li><strong>18 Bedrock vs Java:用另一套架构反观设计取舍</strong> (C++ ECS vs JVM OO / LevelDB vs Anvil/NBT / RakNet UDP vs TCP / 性能与平台 / 红石刷怪含水差异根源)</li><li><strong>19 性能诊断:lag 来源、profiler 与优化生态</strong> (TPS vs FPS vs MSPT / 掉 TPS 来源拆解 / spark/tick/F3 / Lithium·Starlight·C2ME·Sodium / 先测后优的方法论)</li><li><strong>20 客户端渲染管线全貌</strong> (游戏线程 vs 渲染线程 / RenderType solid/cutout/translucent 与排序 / 视锥剔除与 cave culling / 实体与方块实体渲染器 / lightmap 与平滑光照 AO / Sodium)</li><li><strong>21 指令、函数与谓词系统</strong> (Brigadier 命令树与补全同步 / 选择器与组件匹配 / mcfunction 与 tick/load 标签 / 谓词·战利品表·进度·配方 / 数据包作为脚本逻辑层)</li></ul><h3 id="第五层-客户端资产、ai-生态与维度细节-22-25" tabindex="-1">第五层:客户端资产、AI 生态与维度细节 (22-25) <a class="header-anchor" href="#第五层-客户端资产、ai-生态与维度细节-22-25" aria-label="Permalink to &quot;第五层:客户端资产、AI 生态与维度细节 (22-25)&quot;">​</a></h3><blockquote><p>收口层:补全唯一还缺的客户端&quot;资产管线&quot;主梁,并把 AI/村民、扩展生态、维度机制三个细分专题讲透。</p></blockquote><ul><li><strong>22 客户端资源与模型系统:blockstate、模型与图集</strong> (resource pack vs data pack / blockstate JSON 的 variants 与 multipart / model JSON 的 parent·elements·textures·display / 贴图图集 stitching / 烘焙 quad 被 chunk mesher 消费 / tint index 与生物群系着色;服务端 BlockState 在客户端的对偶)</li><li><strong>23 AI 与村民:寻路、Brain 与交易/袭击</strong> (A* 与 NodeEvaluator 代价 / Goal 旧系统 vs Brain 新系统的 Memory·Sensor·Activity·Schedule / 村民职业·工作站 POI·作息·交易经济·声望 gossip / 袭击 raid)</li><li><strong>24 mod 架构:Fabric/Forge 与 Mixin</strong> (无官方 mod API / modloader 引导层 / Fabric·Forge·NeoForge 对比 / 混淆与映射 Yarn·MCP·Mojmap / Mixin 字节码注入与冲突 / 版本脆弱性根源)</li><li><strong>25 维度机制:下界缩放、传送门与末地</strong> (DimensionType 数据驱动属性 / 下界 8:1 坐标缩放 / 传送门搜索配对算法 / 末地折跃门与外岛 / 自定义维度 / 各维度独立 chunk 存储)</li></ul><blockquote><p><strong>另有 4 处随篇增补</strong>(非独立成篇,折进相关章节):时间/昼夜/月相/天气 → 第 04 篇;声音 SoundEvent → 第 10 篇;附魔/铁砧数值 → 第 11 篇;区域难度 Local Difficulty → 第 15 篇。</p></blockquote><hr><h2 id="贯穿视角" tabindex="-1">贯穿视角 <a class="header-anchor" href="#贯穿视角" aria-label="Permalink to &quot;贯穿视角&quot;">​</a></h2><p>全系列围绕一个反复出现的核心洞察展开,而不是堆砌孤立知识点:</p><blockquote><p><strong>Minecraft 的省与快,几乎都来自同一招——&quot;能算出来的就不存,能共享的就不复制&quot;。</strong> 地形靠种子+噪声确定性生成(不存)、方块靠 BlockState 共享+调色板下标(不复制)、内存结构与磁盘结构同构(不转换)。</p></blockquote><table tabindex="0"><thead><tr><th>篇目</th><th>这一招的体现</th></tr></thead><tbody><tr><td>01 / 02</td><td>无限地形不存,靠种子+噪声现算</td></tr><tr><td>03 / 08</td><td>内存 PalettedContainer 与磁盘 palette 同构,加载几乎零转换</td></tr><tr><td>07 / 08</td><td>只存改过的 chunk;局部调色板把均质地形压到近乎为零</td></tr><tr><td>09</td><td>方块无逐实例数据,千万个石头共享一个 BlendState 引用</td></tr></tbody></table><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>噪声、插值、随机数学</td><td>mathForCS</td><td>只讲在地形生成与 random tick 里的工程用法</td></tr><tr><td>游戏引擎、场景树、渲染管线</td><td>godotLearning</td><td>不重复通用引擎概念,只讲体素世界特有的组织与渲染</td></tr><tr><td>序列化、压缩、文件格式通论</td><td>backendLearning / dataEngineering</td><td>不讲通用序列化理论,只讲 NBT/Anvil 的具体设计与取舍</td></tr><tr><td>注册表 / 数据驱动架构模式</td><td>designPatternLearning</td><td>不讲模式定义,只讲 Minecraft 注册表与数据包的落地</td></tr></tbody></table><hr><h2 id="单篇写作模板" tabindex="-1">单篇写作模板 <a class="header-anchor" href="#单篇写作模板" aria-label="Permalink to &quot;单篇写作模板&quot;">​</a></h2><p>每篇尽量遵循固定结构,避免变成散点知识:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 问题定位</span></span>
<span class="line"><span>   - 这个机制要解决体素世界里的什么核心难题</span></span>
<span class="line"><span>   - 朴素做法为什么扛不住(性能 / 存储 / 一致性)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 设计与结构</span></span>
<span class="line"><span>   - 核心数据结构、对象或文件布局</span></span>
<span class="line"><span>   - 关键算法或运行流程</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 下沉细节</span></span>
<span class="line"><span>   - 字节级布局 / 位运算 / 调度顺序等关键处展开</span></span>
<span class="line"><span>   - 版本演进带来的差异</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 取舍与边界</span></span>
<span class="line"><span>   - 为什么这样设计、牺牲了什么换了什么</span></span>
<span class="line"><span>   - 常见误解与反直觉点</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 串联</span></span>
<span class="line"><span>   - 与前后篇、与&quot;能算不存、能享不复制&quot;主线的呼应</span></span></code></pre></div><hr><h2 id="章节节奏" tabindex="-1">章节节奏 <a class="header-anchor" href="#章节节奏" aria-label="Permalink to &quot;章节节奏&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-03 生成与呈现:体素世界怎么组织、地形怎么算出来、区块怎么高效画出来</span></span>
<span class="line"><span>04-06 运行:20 TPS 怎么驱动方块与实体、区块的加载等级、实体系统</span></span>
<span class="line"><span>07-08 存储:Region/Anvil 文件格式与 NBT/Palette 压缩</span></span>
<span class="line"><span>09-12 对象模型:方块三层、其它对象类别、注册表元系统,最后收成架构总图</span></span></code></pre></div>`,44)])])}const g=a(i,[["render",o]]);export{h as __pageData,g as default};
